const char*sfbs_text(Language l,TextId id){if(l<0||l>=LANG_COUNT)l=LANG_EN;if(id<0||id>=TXT_COUNT)return"";return text[l][id];}
const char*sfbs_language_name(Language l){return names[l>=0&&l<LANG_COUNT?l:LANG_EN];}
const char*sfbs_result_text(Language l,int p){return sfbs_text(l,p==100?TXT_RESULT_PERFECT:p>=90?TXT_RESULT_NEAR:p>=70?TXT_RESULT_RESTORED:p>=40?TXT_RESULT_PARTIAL:TXT_RESULT_FRAGMENT);}
